CREATE OR REPLACE FUNCTION fpa_com_cal_agetext_mr (adt_bdate timestamp(0), adt_edate timestamp(0)) RETURNS varchar AS $body$
DECLARE

  /*adt_bdate - วันที่เริ่มต้น ,adt_edate - วันที่สิ้นสุด */

  li_year integer := 0; --ปี
  li_month integer := 0;--เดือน
  li_date integer := 0;--วันที่
  ls_return varchar(100);--ผลลัพธ์
BEGIN
--การคำนวนแบบพิเศษ  ปัดขึ้นทั้งหมด 1 วันคิดเป็น 1 เดือน 5 เดือนคิดเป็น 1 ปี
   if adt_edate > adt_bdate then
    -- ปี
     li_year :=  date_trunc('day', pka_srv_datetime.fp_MonthsAfter(adt_bdate,adt_edate)/12);
    --เดือน , วัน
      li_date := sign(date_trunc('day', adt_edate) - adt_bdate + pka_srv_datetime.fp_MonthsAfter(adt_bdate,adt_edate)*'1 month'::interval);
      if li_date = -1 then
         li_month := date_trunc('day', mod(months_between(adt_edate, adt_bdate),12))-1;
         li_date := 0;--เคีลยร์ค่า
         li_date := adt_edate - (adt_bdate + pka_srv_datetime.fp_MonthsAfter(adt_bdate,adt_edate)-1*'1 month'::interval);
      else
        li_month := date_trunc('day', mod(months_between(adt_edate, adt_bdate),12));
        li_date := 0;--เคีลยร์ค่า
        li_date := adt_edate - adt_bdate + pka_srv_datetime.fp_MonthsAfter(adt_bdate,adt_edate)*'1 month'::interval;
      end if;
   end if;
 -- การแสดงผล
 if li_date > 0 then
    li_month := li_month + 1;
 end if;
 if li_month > 5 then
    li_year := li_year + 1;
 end if;
 ls_return := li_year;

return trim(both ls_return);

exception when others then CALL spa_dberror('FPA_COM_CAL_AGETEXT_MR');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
